    var hlBase  = slide.variant === 'cover' ? 7.7 : 6.3;
    var subBase = 4.4;
    var hlSize  = (hlBase  * ((slide.headlineSize    || 100) / 100)).toFixed(3) + 'cqw';
    var subSize = (subBase * ((slide.subheadlineSize || 100) / 100)).toFixed(3) + 'cqw';

    // Área de imagem / bullets / divisor
    var imgHtml = '';
    if (slide.variant === 'bullets') {
      var bulletItems = (slide.bullets || []).slice(0, 4).map(function (b, i) {
        var sep = i > 0
          ? '<div style="width:100%;height:1px;background:' + (dark ? 'rgba(255,255,255,0.1)' : 'rgba(0,0,0,0.1)') + ';margin:2.8cqw 0;"></div>'
          : '';
        return (
          '<div>' + sep +
            '<div style="display:flex;align-items:center;gap:4%;">' +
              '<span style="flex-shrink:0;font-weight:900;color:' + accent + ';min-width:5cqw;font-size:calc(' + subSize + ' * 0.8);line-height:1;letter-spacing:-0.04em;">' + String(i+1).padStart(2,'0') + '</span>' +
              '<span style="flex:1;font-weight:700;line-height:1.25;letter-spacing:-0.03em;font-size:' + subSize + ';">' + esc(b) + '</span>' +
            '</div>' +
          '</div>'
        );
      }).join('');
      imgHtml = '<div style="flex:1;min-height:0;display:flex;flex-direction:column;justify-content:center;margin:2% 0;">' + bulletItems + '</div>';
