                model="claude-sonnet-4-5",
                max_tokens=512,
                messages=[{"role": "user", "content": prompt}]
            )
            analise = msg.content[0].text
            brain.salvar(
                modulo="Financeiro",
                titulo=f"Análise financeira {mes}",
                inputs={
                    "mes": mes,
                    "receita": receita,
                    "despesas": despesas,
                    "saldo": saldo,
                    "receita_anterior": receita_ant,
                    "despesas_anteriores": desp_ant,
                },
                output=analise,
                model="claude-sonnet-4-5",
            )
