/* ──────────────────────────────────────────────────────
   Jake OS — Gerador de Carrossel
   Vanilla JS, sem dependências externas.
────────────────────────────────────────────────────── */
(function () {
  'use strict';

  // ── Perfis de conta ──────────────────────────────────────────────────────
  var PERFIS = {
    brunozatti: {
      username:   '@brunozatii',
      accentColor: '#003cbb',
    },
    belibid: {
      username:   '@belibid_oficial',
      accentColor: '#ce5f70',
    },
  };

  function getPerfil() {
    var sel = document.getElementById('cs-perfil');
    var key = sel ? sel.value : 'brunozatti';
    return PERFIS[key] || PERFIS.brunozatti;
  }

  // ── Dados padrão ─────────────────────────────────────────────────────────
  function makeDefaultSlides() {
    var p = getPerfil();
    return [
      { id: '01', headline: 'Título principal aqui',   subheadline: 'Subtítulo de apoio que complementa o gancho.',      tag: 'GANCHO',   variant: 'cover',     contentOffset: 0 },
      { id: '02', headline: 'O problema real',         subheadline: 'Detalhe do problema que o seu público enfrenta.',    tag: 'PROBLEMA', variant: 'split',     contentOffset: 0 },
      { id: '03', headline: 'Por que isso acontece?',  subheadline: 'A raiz da questão que poucos abordam com clareza.',  tag: 'PROBLEMA', variant: 'split',     contentOffset: 0 },
      { id: '04', headline: 'A solução existe',        subheadline: 'Apresentando o caminho que transforma o resultado.',  tag: 'SOLUÇÃO',  variant: 'split',     contentOffset: 0 },
      { id: '05', headline: 'O método em 3 passos',     subheadline: '',                                                  tag: 'VALOR',    variant: 'bullets',  bullets: ['Identifique o problema raiz', 'Aplique o método testado', 'Mensure e escale'], contentOffset: 0 },
      { id: '06', headline: 'Resultado concreto',      subheadline: 'O que você vai alcançar aplicando este framework.',  tag: 'VALOR',    variant: 'statement', contentOffset: 0 },
      { id: '07', headline: 'Próximo passo',           subheadline: 'Como começar agora e colher resultados reais.',      tag: 'CTA',      variant: 'closing',  ctaText: 'Siga ' + p.username + ' para mais conteúdos', contentOffset: 0 },
    ];
  }

  // ── Presets de CTA ───────────────────────────────────────────────────────
  function getCTAPresets() {
    var p = getPerfil();
    return [
      'Siga ' + p.username + ' para mais conteúdos',
      'Me segue pra não perder o próximo',
      'Salve esse post pra consultar depois',
      'Compartilhe com quem precisa disso',
      "Comente 'QUERO' e te mando mais",
      'Acesse o link na bio',
    ];
  }

  // ── Estado global ────────────────────────────────────────────────────────
  var slides      = makeDefaultSlides();
  var activeSlide = '01';
  var tone        = 'elegante';
  var generating  = false;

  // ── Utilidades ────────────────────────────────────────────────────────────
  function deepClone(obj) { return JSON.parse(JSON.stringify(obj)); }

  function esc(str) {
    return String(str || '')
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;');
  }

  function getActive() {
    return slides.find(function (s) { return s.id === activeSlide; }) || slides[0];
  }

  function getActiveIndex() {
    return slides.findIndex(function (s) { return s.id === activeSlide; });
  }

  function updateSlide(id, field, value) {
    slides = slides.map(function (s) {
      if (s.id !== id) return s;
      var updated = deepClone(s);
      updated[field] = value;
      return updated;
    });
  }

  // ── Renderizador de slide (HTML/CSS puro) ────────────────────────────────
  function renderSlideHTML(slide, index, compact) {
    var perfil    = getPerfil();
    var accent    = perfil.accentColor;
    var username  = perfil.username;
    var dark      = !slide.lightMode;
    var bg        = dark ? '#02021a' : '#f5f5f7';
    var textMain  = dark ? '#f2f2de' : '#111126';
    var textMeta  = dark ? 'rgba(242,242,222,0.7)' : 'rgba(17,17,38,0.65)';

    // Tamanhos base ligeiramente menores para dar mais respiro em relação à listra azul
    var hlBase  = slide.variant === 'cover' ? 7.7 : 6.3;
    var subBase = 4.4;
    var hlSize  = (hlBase  * ((slide.headlineSize    || 100) / 100)).toFixed(3) + 'cqw';
    var subSize = (subBase * ((slide.subheadlineSize || 100) / 100)).toFixed(3) + 'cqw';

    // Área de imagem / bullets / divisor
    var imgHtml = '';
    if (slide.variant === 'bullets') {
      var bulletItems = (slide.bullets || []).slice(0, 4).map(function (b, i) {
        var sep = i > 0
          ? '<div style="width:100%;height:1px;background:' + (dark ? 'rgba(255,255,255,0.1)' : 'rgba(0,0,0,0.1)') + ';margin:2.8cqw 0;"></div>'
          : '';
        return (
          '<div>' + sep +
            '<div style="display:flex;align-items:center;gap:4%;">' +
              '<span style="flex-shrink:0;font-weight:900;color:' + accent + ';min-width:5cqw;font-size:calc(' + subSize + ' * 0.8);line-height:1;letter-spacing:-0.04em;">' + String(i+1).padStart(2,'0') + '</span>' +
              '<span style="flex:1;font-weight:700;line-height:1.25;letter-spacing:-0.03em;font-size:' + subSize + ';">' + esc(b) + '</span>' +
            '</div>' +
          '</div>'
        );
      }).join('');
      imgHtml = '<div style="flex:1;min-height:0;display:flex;flex-direction:column;justify-content:center;margin:2% 0;">' + bulletItems + '</div>';
    } else if (slide.variant === 'statement') {
      imgHtml = '<div style="height:2px;width:100%;background:' + accent + '38;border-radius:4px;margin-bottom:5%;flex-shrink:0;"></div>';
    } else {
      var overlay = (slide.backgroundImage && dark)
        ? '<div style="position:absolute;inset:0;background:rgba(0,0,0,' + (slide.overlayOpacity || 0.35) + ');"></div>'
        : '';
      var imgPosX = (slide.imagePosX !== undefined ? slide.imagePosX : 50) + '%';
      var imgPosY = (slide.imagePosY !== undefined ? slide.imagePosY : 50) + '%';
      var imgInner = slide.backgroundImage
        ? '<div style="position:absolute;inset:0;background-image:url(\'' + esc(slide.backgroundImage) + '\');background-size:cover;background-position:' + imgPosX + ' ' + imgPosY + ';' + (slide.grayscale ? 'filter:grayscale(1);' : '') + '"></div>' + overlay
        : '<div style="display:flex;height:100%;align-items:center;justify-content:center;font-size:10px;opacity:0.3;color:' + textMain + ';">sem imagem</div>';
      // Mais respiro entre imagem e texto de baixo
      imgHtml = '<div style="position:relative;height:36cqw;flex-shrink:0;overflow:hidden;border-radius:12px;background:' + (dark ? 'rgba(0,0,0,0.15)' : 'rgba(200,200,210,0.4)') + ';margin-bottom:5.5%;">' + imgInner + '</div>';
    }

    // Badge CTA — no closing: área reservada para o CTA (texto não invade)
    var ctaBadgeText = slide.ctaText || getCTAPresets()[0];
    var ctaHtml = slide.variant === 'closing'
      ? '<div style="flex-shrink:0;min-height:10%;padding-top:4%;margin-top:auto;"><div style="display:inline-block;border:1px solid ' + (dark ? 'rgba(242,242,222,0.35)' : 'rgba(17,17,38,0.3)') + ';border-radius:9999px;padding:4px 12px;font-size:9px;font-weight:500;color:' + (dark ? 'rgba(242,242,222,0.8)' : 'rgba(17,17,38,0.7)') + ';">' + esc(ctaBadgeText) + '</div></div>'
      : '';

    // Dots de navegação
    var dotsHtml = Array.from({ length: slides.length }, function (_, i) {
      var isActive = i === index;
      return '<div style="border-radius:9999px;' + (isActive
        ? 'width:16px;height:6px;background:' + (dark ? '#f2f2de' : '#111126') + ';'
        : 'width:6px;height:6px;background:' + (dark ? 'rgba(242,242,222,0.25)' : 'rgba(17,17,38,0.25)') + ';') + '"></div>';
    }).join('');

    var navHtml = compact
      ? '<div style="margin-top:auto;padding-top:3%;display:flex;gap:5px;">' + dotsHtml + '</div>'
      : '<div style="margin-top:auto;display:flex;align-items:center;justify-content:space-between;padding-top:4%;"><div style="width:28px;"></div><div style="display:flex;gap:5px;">' + dotsHtml + '</div><div style="width:28px;"></div></div>';

    var contentBlock = '<h2 style="font-weight:900;letter-spacing:-0.05em;line-height:1.06;margin:2% 0 5% 0;font-size:' + hlSize + ';overflow:hidden;display:-webkit-box;-webkit-line-clamp:3;-webkit-box-orient:vertical;">' + esc(slide.headline) + '</h2>' +
      imgHtml +
      (slide.variant !== 'bullets' ? '<p style="font-weight:600;letter-spacing:-0.02em;line-height:1.3;margin:1.5% 0 0 0;font-size:' + subSize + ';overflow:hidden;display:-webkit-box;-webkit-line-clamp:4;-webkit-box-orient:vertical;">' + esc(slide.subheadline) + '</p>' : '');
    var offset = slide.contentOffset || 0;
    var contentWrapperStyle = 'flex:1;min-height:0;overflow:hidden;display:flex;flex-direction:column;transform:translateY(' + offset + '%);transition:transform .15s ease-out;';
    contentBlock = '<div style="' + contentWrapperStyle + '">' + contentBlock + '</div>';
    return (
      '<div style="position:relative;width:100%;aspect-ratio:4/5;overflow:hidden;container-type:inline-size;background:' + bg + ';color:' + textMain + ';font-family:Inter,Rajdhani,sans-serif;border-radius:inherit;">' +
        '<div style="position:absolute;inset:0;display:flex;flex-direction:column;padding:7%;">' +
          '<div style="display:flex;align-items:center;justify-content:space-between;font-size:2.1cqw;margin-bottom:4%;color:' + textMeta + ';font-weight:500;">' +
            '<span>' + username + '</span><span>Fevereiro 2026 &#174;</span>' +
          '</div>' +
          '<div style="display:flex;align-items:center;gap:3%;margin-bottom:3%;flex-shrink:0;">' +
            '<div style="width:7cqw;height:2px;background:' + accent + ';border-radius:9999px;flex-shrink:0;"></div>' +
            '<div style="flex:1;height:2px;background:' + accent + '38;border-radius:9999px;"></div>' +
          '</div>' +
          contentBlock +
          ctaHtml +
          navHtml +
        '</div>' +
      '</div>'
    );
  }

  // ── Mini-grid ─────────────────────────────────────────────────────────────
  function renderMiniGrid() {
    var grid = document.getElementById('cs-mini-grid');
    if (!grid) return;
    grid.innerHTML = slides.map(function (slide, i) {
      var isActive = slide.id === activeSlide;
      return (
        '<button type="button" class="cs-mini-btn' + (isActive ? ' active' : '') + '" data-slide-id="' + slide.id + '">' +
          '<div class="cs-mini-inner">' + renderSlideHTML(slide, i, true) + '</div>' +
          '<div class="cs-mini-footer' + (isActive ? ' active' : '') + '">' +
            '<span>' + String(i + 1).padStart(2, '0') + '</span>' +
            '<span>' + esc({ cover: 'Capa', split: 'Texto+Img', statement: 'Statement', closing: 'Fechamento' }[slide.variant] || slide.variant) + '</span>' +
          '</div>' +
        '</button>'
      );
    }).join('');

    grid.querySelectorAll('.cs-mini-btn').forEach(function (btn) {
      btn.addEventListener('click', function () {
        activeSlide = btn.dataset.slideId;
        renderAll();
      });
    });
  }

  // ── Preview do slide ativo ────────────────────────────────────────────────
  function renderActivePreview() {
    var wrap  = document.getElementById('cs-preview-wrap');
    var label = document.getElementById('cs-preview-id');
    if (!wrap) return;
    var slide = getActive();
    var index = getActiveIndex();
    wrap.innerHTML = renderSlideHTML(slide, index, false);
    if (label) label.textContent = slide.id;
  }

  // ── Tamanho global (headline/subheadline para todos os slides) ───────────
  var globalHlSize  = 100;
  var globalSubSize = 100;

  function applyGlobalSizes() {
    slides = slides.map(function (s) {
      var updated = deepClone(s);
      updated.headlineSize    = globalHlSize;
      updated.subheadlineSize = globalSubSize;
      return updated;
    });
  }

  // ── Painel de edição ─────────────────────────────────────────────────────
  function syncEditor() {
    var slide = getActive();

    var setVal = function (id, val) { var el = document.getElementById(id); if (el) el.value = val; };
    var setText = function (id, val) { var el = document.getElementById(id); if (el) el.textContent = val; };

    setText('cs-edit-id', slide.id);
    setVal('cs-headline',    slide.headline    || '');
    setVal('cs-subheadline', slide.subheadline || '');
    setVal('cs-tag',         slide.tag         || '');

    // CTA selector — só aparece no slide closing
    var ctaBlock = document.getElementById('cs-cta-block');
    if (ctaBlock) {
      if (slide.variant === 'closing') {
        ctaBlock.classList.remove('hidden');
        var currentCta = slide.ctaText || getCTAPresets()[0];
        ctaBlock.querySelectorAll('.cs-cta-preset').forEach(function (btn) {
          btn.classList.toggle('active', btn.dataset.cta === currentCta);
        });
        var customInput = document.getElementById('cs-cta-custom');
        if (customInput) {
          customInput.value = getCTAPresets().includes(currentCta) ? '' : currentCta;
        }
      } else {
        ctaBlock.classList.add('hidden');
      }
    }

    // Bullets editor — só aparece no slide bullets
    var bulletsBlock = document.getElementById('cs-bullets-block');
    if (bulletsBlock) {
      if (slide.variant === 'bullets') {
        bulletsBlock.classList.remove('hidden');
        var bulletsTA = document.getElementById('cs-bullets-ta');
        if (bulletsTA) bulletsTA.value = (slide.bullets || []).join('\n');
      } else {
        bulletsBlock.classList.add('hidden');
      }
    }

    // Offset vertical do conteúdo (por slide)
    setVal('cs-content-offset', slide.contentOffset != null ? slide.contentOffset : 0);

    // Sliders globais
    setVal('cs-g-hl-size',  globalHlSize);
    setVal('cs-g-sub-size', globalSubSize);
    setText('cs-g-hl-val',  globalHlSize  + '%');
    setText('cs-g-sub-val', globalSubSize + '%');

    var tagBadge = document.getElementById('cs-edit-tag-badge');
    if (tagBadge) tagBadge.textContent = slide.tag || '';

    document.querySelectorAll('.cs-mode-btn').forEach(function (btn) {
      btn.classList.toggle('active', btn.dataset.mode === (slide.lightMode ? 'light' : 'dark'));
    });
    document.querySelectorAll('.cs-variant-btn').forEach(function (btn) {
      btn.classList.toggle('active', btn.dataset.variant === (slide.variant || 'split'));
    });

    var imgPreview     = document.getElementById('cs-img-preview');
    var imgPlaceholder = document.getElementById('cs-img-placeholder');
    var imgControls    = document.getElementById('cs-img-controls');
    var grayscale      = document.getElementById('cs-grayscale');

    if (slide.backgroundImage) {
      if (imgPreview)     { imgPreview.src = slide.backgroundImage; imgPreview.classList.remove('hidden'); }
      if (imgPlaceholder) imgPlaceholder.classList.add('hidden');
      if (imgControls)    imgControls.classList.remove('hidden');
    } else {
      if (imgPreview)     { imgPreview.src = ''; imgPreview.classList.add('hidden'); }
      if (imgPlaceholder) imgPlaceholder.classList.remove('hidden');
      if (imgControls)    imgControls.classList.add('hidden');
    }
    if (grayscale) grayscale.checked = !!slide.grayscale;
  }

  // ── Render completo ───────────────────────────────────────────────────────
  function renderAll() {
    renderMiniGrid();
    renderActivePreview();
    syncEditor();
  }

  // ── Compressão de imagem ─────────────────────────────────────────────────
  function compressImage(dataUrl, maxDim, quality, cb) {
    maxDim   = maxDim   || 1200;
    quality  = quality  || 0.82;
    if (!dataUrl || !dataUrl.startsWith('data:image')) { cb(dataUrl); return; }
    var img = new Image();
    img.onload = function () {
      var scale = (img.width > maxDim || img.height > maxDim)
        ? Math.min(maxDim / img.width, maxDim / img.height) : 1;
      var canvas = document.createElement('canvas');
      canvas.width  = Math.round(img.width  * scale);
      canvas.height = Math.round(img.height * scale);
      var ctx = canvas.getContext('2d');
      if (!ctx) { cb(dataUrl); return; }
      ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
      cb(canvas.toDataURL('image/jpeg', quality));
    };
    img.onerror = function () { cb(dataUrl); };
    img.src = dataUrl;
  }

  function handleImageFile(file) {
    if (!file) return;
    var reader = new FileReader();
    reader.onload = function (e) {
      compressImage(e.target.result, 1200, 0.82, function (compressed) {
        updateSlide(activeSlide, 'backgroundImage', compressed);
        renderAll();
      });
    };
    reader.readAsDataURL(file);
  }

  // ── Upload em lote ────────────────────────────────────────────────────────
  function handleBatchUpload(files) {
    if (!files || files.length === 0) return;
    var fileArr = Array.prototype.slice.call(files, 0, 7);
    var total   = fileArr.length;
    var done    = 0;

    var statusEl = document.getElementById('cs-batch-status');
    if (statusEl) {
      statusEl.textContent = 'Processando 0/' + total + '...';
      statusEl.className   = 'cs-batch-status visible loading';
    }

    fileArr.forEach(function (file, i) {
      var reader = new FileReader();
      reader.onload = function (ev) {
        compressImage(ev.target.result, 1200, 0.82, function (compressed) {
          updateSlide(slides[i].id, 'backgroundImage', compressed);
          done++;
          if (statusEl) statusEl.textContent = 'Processando ' + done + '/' + total + '...';
          if (done === total) {
            if (statusEl) {
              statusEl.textContent = '✓ ' + total + ' imagem' + (total > 1 ? 'ns' : '') + ' aplicada' + (total > 1 ? 's' : '') + '!';
              statusEl.className   = 'cs-batch-status visible ok';
              setTimeout(function () { statusEl.className = 'cs-batch-status hidden'; }, 3500);
            }
            // Ativa o primeiro slide com imagem
            activeSlide = slides[0].id;
            renderAll();
          }
        });
      };
      reader.readAsDataURL(file);
    });
  }

  // ── Gerar copy com IA ─────────────────────────────────────────────────────
  function generateCopy() {
    if (generating) return;
    var themeEl = document.getElementById('cs-theme');
    var theme   = themeEl ? themeEl.value.trim() : '';
    if (theme.length < 3) {
      showStatus('Digite um tema com pelo menos 3 caracteres.', 'error');
      return;
    }

    var awarenessEl = document.getElementById('cs-awareness');
    var triggerEl   = document.getElementById('cs-trigger');
    var awareness   = awarenessEl ? awarenessEl.value : '';
    var trigger     = triggerEl   ? triggerEl.value   : '';

    generating = true;
    var btn = document.getElementById('cs-gen-btn');
    if (btn) { btn.disabled = true; btn.innerHTML = '<span>⟳</span> Gerando...'; }
    showStatus('Gerando copy com IA, aguarde...', 'loading');

    var numSlidesEl = document.getElementById('cs-num-slides');
    var numSlides = numSlidesEl ? parseInt(numSlidesEl.value, 10) : 7;
    var defaultSlides = makeDefaultSlides();

    fetch('/api/carousel/copy', {
      method:  'POST',
      headers: { 'Content-Type': 'application/json' },
      body:    JSON.stringify({ theme: theme, tone: tone, awareness: awareness, trigger: trigger, num_slides: numSlides }),
    })
      .then(function (r) { return r.json(); })
      .then(function (data) {
        if (data.slides && data.slides.length >= 3) {
          slides = data.slides.map(function (s, i) {
            var base = deepClone(slides[i] || defaultSlides[i] || defaultSlides[defaultSlides.length - 1]);
            base.headline    = s.headline    || base.headline;
            base.subheadline = s.subheadline || base.subheadline;
            base.tag         = s.tag         || base.tag;
            base.id          = String(i + 1).padStart(2, '0');
            return base;
          });
          activeSlide = slides[0].id;
          showStatus(data.error ? '⚠ Fallback usado — verifique a IA.' : '✓ Copy gerada com sucesso!',
                     data.error ? 'warn' : 'ok');
          renderAll();
        } else {
          showStatus('Erro ao gerar copy. Tente novamente.', 'error');
        }
      })
      .catch(function () {
        showStatus('Erro de conexão. Tente novamente.', 'error');
      })
      .finally(function () {
        generating = false;
        if (btn) { btn.disabled = false; btn.innerHTML = '<span>✦</span> Gerar com IA'; }
        setTimeout(hideStatus, 4000);
      });
  }

  // ── Status ────────────────────────────────────────────────────────────────
  function showStatus(msg, type) {
    var el = document.getElementById('cs-status');
    if (!el) return;
    el.textContent = msg;
    el.className   = 'cs-status cs-status-' + (type || 'ok') + ' visible';
  }
  function hideStatus() {
    var el = document.getElementById('cs-status');
    if (el) el.className = 'cs-status';
  }

  // ── Canvas renderer 1080×1350 (Instagram-ready PNGs) ────────────────────
  var SLIDE_W = 1080;
  var SLIDE_H = 1350;
  var PAD     = 80;

  function _canvasRoundRect(ctx, x, y, w, h, r) {
    ctx.beginPath();
    ctx.moveTo(x + r, y);
    ctx.lineTo(x + w - r, y);
    ctx.quadraticCurveTo(x + w, y, x + w, y + r);
    ctx.lineTo(x + w, y + h - r);
    ctx.quadraticCurveTo(x + w, y + h, x + w - r, y + h);
    ctx.lineTo(x + r, y + h);
    ctx.quadraticCurveTo(x, y + h, x, y + h - r);
    ctx.lineTo(x, y + r);
    ctx.quadraticCurveTo(x, y, x + r, y);
    ctx.closePath();
  }

  function _wrapText(ctx, text, x, y, maxW, lineH, maxHeight) {
    var words = String(text || '').split(' ');
    var line  = '';
    var drawn = 0;
    for (var i = 0; i < words.length; i++) {
      if (maxHeight != null && (drawn + 1) * lineH > maxHeight) break;
      var test = line + (line ? ' ' : '') + words[i];
      if (ctx.measureText(test).width > maxW && line !== '') {
        ctx.fillText(line, x, y + drawn * lineH);
        line = words[i];
        drawn++;
      } else {
        line = test;
      }
    }
    if (line && (maxHeight == null || (drawn + 1) * lineH <= maxHeight)) {
      ctx.fillText(line, x, y + drawn * lineH);
      drawn++;
    }
    return drawn * lineH;
  }

  function _loadImg(src) {
    return new Promise(function (resolve) {
      if (!src) { resolve(null); return; }
      var img = new Image();
      img.crossOrigin = 'anonymous';
      img.onload  = function () { resolve(img); };
      img.onerror = function () { resolve(null); };
      img.src = src;
    });
  }

  function renderSlideToPng(slide, index) {
    return document.fonts.ready.then(function () {
      return _loadImg(slide.backgroundImage || null);
    }).then(function (bgImg) {
      var canvas  = document.createElement('canvas');
      canvas.width  = SLIDE_W;
      canvas.height = SLIDE_H;
      var ctx = canvas.getContext('2d');

      var perfil_  = getPerfil();
      var accent_  = perfil_.accentColor;
      var username_= perfil_.username;
      var dark     = !slide.lightMode;
      var bg       = dark ? '#02021a' : '#f5f5f7';
      var textMain = dark ? '#f2f2de' : '#111126';
      var textMeta = dark ? 'rgba(242,242,222,0.70)' : 'rgba(17,17,38,0.65)';
      var imgBg    = dark ? '#121229' : '#E2E2E9';
      var maxW     = SLIDE_W - PAD * 2;

      // Background
      ctx.fillStyle = bg;
      ctx.fillRect(0, 0, SLIDE_W, SLIDE_H);

      // Header meta
      ctx.font = '500 22px "Inter", sans-serif';
      ctx.textBaseline = 'alphabetic';
      ctx.fillStyle = textMeta;
      ctx.textAlign = 'left';
      ctx.fillText(username_, PAD, PAD + 24);
      ctx.textAlign = 'right';
      ctx.fillText('Fevereiro 2026 \u00ae', SLIDE_W - PAD, PAD + 24);
      ctx.textAlign = 'left';

      var curY = PAD + 62;

      // Accent lines
      ctx.fillStyle = accent_;
      ctx.fillRect(PAD, curY, 80, 3);
      ctx.fillStyle = accent_ + '38';
      ctx.fillRect(PAD + 88, curY, maxW - 88, 3);
      // Mais espaço entre listra azul e título
      curY += 40;

      // Headline
      var hlMult  = (slide.headlineSize || 100) / 100;
      var hlPx    = Math.round((slide.variant === 'cover' ? 84 : 70) * hlMult);
      var hlLineH = Math.round(hlPx * 1.06);
      ctx.font = '900 ' + hlPx + 'px "Inter", sans-serif';
      ctx.fillStyle = textMain;
      var offsetFactor = (slide.contentOffset || 0) / 100;
      var groupOffsetPx = offsetFactor * 60; // afeta bloco de texto principal
      curY += groupOffsetPx;
      var hlH = _wrapText(ctx, slide.headline || '', PAD, curY + hlLineH - hlPx, maxW, hlLineH);
      // Mais respiro entre título e conteúdo
      curY += hlH + 40;

      // Content area: bullets / statement / image
      if (slide.variant === 'bullets') {
        var bItems = (slide.bullets || []).slice(0, 4);
        var bPx    = Math.round(44 * ((slide.subheadlineSize || 100) / 100));
        var bLineH = Math.round(bPx * 1.3);
        ctx.font = '700 ' + bPx + 'px "Inter", sans-serif';
        ctx.fillStyle = textMain;
        bItems.forEach(function (b) {
          ctx.fillStyle = accent_;
          ctx.beginPath();
          ctx.arc(PAD + 8, curY + bPx * 0.35, 8, 0, Math.PI * 2);
          ctx.fill();
          ctx.fillStyle = textMain;
          _wrapText(ctx, b, PAD + 32, curY, maxW - 32, bLineH);
          curY += bLineH + 14;
        });
        curY += 20;
      } else if (slide.variant === 'statement') {
        ctx.fillStyle = accent_ + '38';
        ctx.fillRect(PAD, curY, maxW, 2);
        curY += 30;
      } else {
        var imgAreaH = 420; // fixed height for consistent layout and breathing room

        _canvasRoundRect(ctx, PAD, curY, maxW, imgAreaH, 16);
        ctx.fillStyle = imgBg;
        ctx.fill();

        if (bgImg) {
          ctx.save();
          _canvasRoundRect(ctx, PAD, curY, maxW, imgAreaH, 16);
          ctx.clip();
          // Respect user-defined image position (object-position equivalent)
          var posX = (slide.imagePosX !== undefined ? slide.imagePosX : 50) / 100;
          var posY = (slide.imagePosY !== undefined ? slide.imagePosY : 50) / 100;
          var scale = Math.max(maxW / bgImg.width, imgAreaH / bgImg.height);
          var dw = bgImg.width * scale, dh = bgImg.height * scale;
          var dx = PAD + (maxW - dw) * posX, dy = curY + (imgAreaH - dh) * posY;
          if (slide.grayscale) ctx.filter = 'grayscale(1)';
          ctx.drawImage(bgImg, dx, dy, dw, dh);
          ctx.filter = 'none';
          if (dark) {
            ctx.fillStyle = 'rgba(0,0,0,' + (slide.overlayOpacity || 0.35) + ')';
            ctx.fillRect(PAD, curY, maxW, imgAreaH);
          }
          ctx.restore();
        } else {
          ctx.fillStyle = dark ? 'rgba(242,242,222,0.25)' : 'rgba(17,17,38,0.2)';
          ctx.font = '400 26px "Inter", sans-serif';
          ctx.textAlign = 'center';
          ctx.fillText('Adicione uma imagem', PAD + maxW / 2, curY + imgAreaH / 2 + 10);
          ctx.textAlign = 'left';
        }
        // Mais espaço entre imagem e texto de baixo
        curY += imgAreaH + 40;
      }

      // Subheadline (hidden for bullets variant) — no closing, limitar altura para não invadir área do CTA
      var ctaReservedY = slide.variant === 'closing' ? SLIDE_H - 150 : null;
      if (slide.variant !== 'bullets') {
        var subMult  = (slide.subheadlineSize || 100) / 100;
        var subPx    = Math.round(50 * subMult);
        var subLineH = Math.round(subPx * 1.25);
        ctx.font = '700 ' + subPx + 'px "Inter", sans-serif';
        ctx.fillStyle = textMain;
        var maxSubY = ctaReservedY ? ctaReservedY - 30 : 1e9;
        _wrapText(ctx, slide.subheadline || '', PAD, curY + subLineH - subPx, maxW, subLineH, maxSubY - curY);
        curY += subLineH * 2 + 22;
      }

      // CTA badge — no closing: posição fixa na área reservada
      if (slide.variant === 'closing') {
        var badgeText = slide.ctaText || getCTAPresets()[0];
        var ctaY = SLIDE_H - 130;
        ctx.font = '500 20px "Inter", sans-serif';
        var bw = ctx.measureText(badgeText).width + 40;
        var bh = 38;
        _canvasRoundRect(ctx, PAD, ctaY, bw, bh, 19);
        ctx.strokeStyle = dark ? 'rgba(242,242,222,0.35)' : 'rgba(17,17,38,0.3)';
        ctx.lineWidth = 1;
        ctx.stroke();
        ctx.fillStyle = dark ? 'rgba(242,242,222,0.8)' : 'rgba(17,17,38,0.7)';
        ctx.fillText(badgeText, PAD + 20, ctaY + 25);
      }

      // Navigation dots (bottom)
      var dotY  = SLIDE_H - 68;
      var dotX  = PAD;
      for (var di = 0; di < slides.length; di++) {
        var active = di === index;
        ctx.beginPath();
        if (active) {
          ctx.rect(dotX, dotY, 16, 6);
        } else {
          ctx.arc(dotX + 3, dotY + 3, 3, 0, Math.PI * 2);
        }
        ctx.fillStyle = active
          ? (dark ? '#f2f2de' : '#111126')
          : (dark ? 'rgba(242,242,222,0.25)' : 'rgba(17,17,38,0.25)');
        ctx.fill();
        dotX += active ? 26 : 14;
      }

      // Slide counter (bottom-right)
      ctx.font = '600 22px "Inter", sans-serif';
      ctx.fillStyle = dark ? 'rgba(242,242,222,0.65)' : 'rgba(17,17,38,0.55)';
      ctx.textAlign = 'right';
      ctx.fillText(String(index + 1).padStart(2, '0') + '/' + String(slides.length).padStart(2, '0'), SLIDE_W - PAD, SLIDE_H - 58);
      ctx.textAlign = 'left';

      return canvas.toDataURL('image/png');
    });
  }

  // ── Exportar: Canvas PNG → ZIP ────────────────────────────────────────────
  function exportSlides() {
    if (typeof JSZip === 'undefined') {
      showStatus('JSZip não carregado. Verifique sua conexão.', 'error');
      return;
    }
    var btn = document.getElementById('cs-export-btn');
    if (btn) { btn.disabled = true; btn.textContent = 'Preparando...'; }
    showStatus('Renderizando slides em alta resolução...', 'loading');

    var chain = Promise.resolve([]);
    slides.forEach(function (slide, i) {
      chain = chain.then(function (results) {
        if (btn) btn.textContent = 'Slide ' + (i + 1) + '/' + slides.length + '...';
        return renderSlideToPng(slide, i).then(function (dataUrl) {
          results.push(dataUrl);
          return results;
        });
      });
    });

    chain.then(function (dataUrls) {
      if (btn) btn.textContent = 'Criando ZIP...';
      var zip = new JSZip();
      dataUrls.forEach(function (dataUrl, i) {
        var b64 = dataUrl.replace(/^data:image\/png;base64,/, '');
        zip.file(String(i + 1).padStart(2, '0') + '.png', b64, { base64: true });
      });
      return zip.generateAsync({ type: 'blob' });
    }).then(function (blob) {
      var url = URL.createObjectURL(blob);
      var a   = document.createElement('a');
      a.href     = url;
      a.download = 'carrossel.zip';
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      URL.revokeObjectURL(url);
      showStatus('✓ ' + slides.length + ' PNGs prontos para o Instagram!', 'ok');
      setTimeout(hideStatus, 5000);
    }).catch(function (err) {
      showStatus('Erro ao exportar: ' + (err.message || err), 'error');
    }).finally(function () {
      if (btn) { btn.disabled = false; btn.textContent = '↓ Baixar PNGs (ZIP)'; }
    });
  }

  // ── Embaralhar imagens (copy e estrutura permanecem intactas) ────────────
  function shuffleSlides() {
    // Extrai apenas as imagens na ordem atual
    var images = slides.map(function (s) {
      return {
        backgroundImage:  s.backgroundImage,
        grayscale:        s.grayscale,
        overlayOpacity:   s.overlayOpacity,
      };
    });

    // Fisher-Yates nas imagens
    for (var i = images.length - 1; i > 0; i--) {
      var j = Math.floor(Math.random() * (i + 1));
      var tmp = images[i]; images[i] = images[j]; images[j] = tmp;
    }

    // Reaplica as imagens embaralhadas mantendo copy/estrutura intacta
    slides = slides.map(function (s, idx) {
      var updated = deepClone(s);
      updated.backgroundImage = images[idx].backgroundImage;
      updated.grayscale       = images[idx].grayscale;
      updated.overlayOpacity  = images[idx].overlayOpacity;
      return updated;
    });

    renderAll();
  }

  // ── Inicializar eventos ───────────────────────────────────────────────────
  function bindEvents() {
    // Tone
    document.querySelectorAll('.cs-tone-btn').forEach(function (btn) {
      btn.addEventListener('click', function () {
        tone = btn.dataset.tone;
        document.querySelectorAll('.cs-tone-btn').forEach(function (b) {
          b.classList.toggle('active', b === btn);
        });
      });
    });

    // Quantidade de slides
    var numSlidesSelect = document.getElementById('cs-num-slides');
    if (numSlidesSelect) {
      numSlidesSelect.addEventListener('change', function () {
        var n = parseInt(numSlidesSelect.value, 10);
        var def = makeDefaultSlides();
        // Expande ou contrai mantendo os slides existentes
        if (n > slides.length) {
          for (var i = slides.length; i < n; i++) {
            var tpl = deepClone(def[Math.min(i, def.length - 1)]);
            tpl.id = String(i + 1).padStart(2, '0');
            slides.push(tpl);
          }
        } else {
          slides = slides.slice(0, n);
        }
        activeSlide = slides[0].id;
        renderAll();
      });
    }

    // Gerar copy
    var genBtn = document.getElementById('cs-gen-btn');
    if (genBtn) genBtn.addEventListener('click', generateCopy);

    // Headline
    var hlInput = document.getElementById('cs-headline');
    if (hlInput) {
      hlInput.addEventListener('input', function () {
        updateSlide(activeSlide, 'headline', hlInput.value);
        renderMiniGrid(); renderActivePreview();
      });
    }

    // Subheadline
    var subInput = document.getElementById('cs-subheadline');
    if (subInput) {
      subInput.addEventListener('input', function () {
        updateSlide(activeSlide, 'subheadline', subInput.value);
        renderMiniGrid(); renderActivePreview();
      });
    }

    // Offset vertical do conteúdo (slider por slide)
    var offsetInput = document.getElementById('cs-content-offset');
    if (offsetInput) {
      offsetInput.addEventListener('input', function () {
        var v = Number(offsetInput.value) || 0;
        updateSlide(activeSlide, 'contentOffset', v);
        renderMiniGrid(); renderActivePreview();
      });
    }

    // Tag
    var tagInput = document.getElementById('cs-tag');
    if (tagInput) {
      tagInput.addEventListener('input', function () {
        var v = tagInput.value.toUpperCase();
        updateSlide(activeSlide, 'tag', v);
        var badge = document.getElementById('cs-edit-tag-badge');
        if (badge) badge.textContent = v;
        renderMiniGrid(); renderActivePreview();
      });
    }

    // Sliders globais (afetam todos os slides de uma vez)
    var gHlRange = document.getElementById('cs-g-hl-size');
    var gHlVal   = document.getElementById('cs-g-hl-val');
    if (gHlRange) {
      gHlRange.addEventListener('input', function () {
        globalHlSize = Number(gHlRange.value);
        if (gHlVal) gHlVal.textContent = globalHlSize + '%';
        applyGlobalSizes();
        renderMiniGrid(); renderActivePreview();
      });
    }

    var gSubRange = document.getElementById('cs-g-sub-size');
    var gSubVal   = document.getElementById('cs-g-sub-val');
    if (gSubRange) {
      gSubRange.addEventListener('input', function () {
        globalSubSize = Number(gSubRange.value);
        if (gSubVal) gSubVal.textContent = globalSubSize + '%';
        applyGlobalSizes();
        renderMiniGrid(); renderActivePreview();
      });
    }

    // Modo (dark/light)
    document.querySelectorAll('.cs-mode-btn').forEach(function (btn) {
      btn.addEventListener('click', function () {
        updateSlide(activeSlide, 'lightMode', btn.dataset.mode === 'light');
        renderAll();
      });
    });

    // Variant
    document.querySelectorAll('.cs-variant-btn').forEach(function (btn) {
      btn.addEventListener('click', function () {
        updateSlide(activeSlide, 'variant', btn.dataset.variant);
        renderAll();
      });
    });

    // Populate CTA preset buttons
    function renderCTAPresets() {
      var ctaPresetsEl = document.getElementById('cs-cta-presets');
      if (!ctaPresetsEl) return;
      ctaPresetsEl.innerHTML = '';
      getCTAPresets().forEach(function (preset) {
        var btn = document.createElement('button');
        btn.type = 'button';
        btn.className = 'cs-cta-preset';
        btn.dataset.cta = preset;
        btn.textContent = preset;
        btn.addEventListener('click', function () {
          updateSlide(activeSlide, 'ctaText', preset);
          var customInput = document.getElementById('cs-cta-custom');
          if (customInput) customInput.value = '';
          renderAll();
        });
        ctaPresetsEl.appendChild(btn);
      });
    }
    renderCTAPresets();

    // Troca de perfil → atualiza preview + presets
    var perfilSel = document.getElementById('cs-perfil');
    if (perfilSel) {
      perfilSel.addEventListener('change', function () {
        // Atualiza CTA padrão do slide 07 com o novo @username
        var p = getPerfil();
        var ctaSlide = slides.find(function(s){ return s.id === '07'; });
        if (ctaSlide) {
          var presets = getCTAPresets();
          // Só auto-atualiza se ainda for o CTA padrão de "siga @..."
          if (!ctaSlide.ctaText || ctaSlide.ctaText.startsWith('Siga @')) {
            updateSlide('07', 'ctaText', presets[0]);
          }
        }
        renderCTAPresets();
        renderAll();
      });
    }

    // CTA custom input
    var ctaCustom = document.getElementById('cs-cta-custom');
    if (ctaCustom) {
      ctaCustom.addEventListener('input', function () {
        if (ctaCustom.value.trim()) {
          updateSlide(activeSlide, 'ctaText', ctaCustom.value.trim());
          var presetBtns = document.querySelectorAll('.cs-cta-preset');
          presetBtns.forEach(function (b) { b.classList.remove('active'); });
          renderAll();
        }
      });
    }

    // Bullets textarea
    var bulletsTA = document.getElementById('cs-bullets-ta');
    if (bulletsTA) {
      bulletsTA.addEventListener('input', function () {
        var lines = bulletsTA.value.split('\n').filter(function (l) { return l.trim().length > 0; }).slice(0, 4);
        updateSlide(activeSlide, 'bullets', lines);
        renderAll();
      });
    }

    // Image upload / drag & drop
    var imgDrop  = document.getElementById('cs-img-drop');
    var imgInput = document.getElementById('cs-img-input');
    if (imgDrop && imgInput) {
      imgDrop.addEventListener('click', function (e) {
        if (e.target === imgInput) return;
        imgInput.click();
      });
      imgDrop.addEventListener('dragover', function (e) {
        e.preventDefault(); imgDrop.classList.add('drag-over');
      });
      imgDrop.addEventListener('dragleave', function () {
        imgDrop.classList.remove('drag-over');
      });
      imgDrop.addEventListener('drop', function (e) {
        e.preventDefault();
        imgDrop.classList.remove('drag-over');
        if (e.dataTransfer.files[0]) handleImageFile(e.dataTransfer.files[0]);
      });
      imgInput.addEventListener('change', function (e) {
        if (e.target.files[0]) handleImageFile(e.target.files[0]);
      });
    }

    // Grayscale
    var grayscale = document.getElementById('cs-grayscale');
    if (grayscale) {
      grayscale.addEventListener('change', function () {
        updateSlide(activeSlide, 'grayscale', grayscale.checked);
        renderMiniGrid(); renderActivePreview();
      });
    }

    // Remover imagem
    var removeImg = document.getElementById('cs-remove-img');
    if (removeImg) {
      removeImg.addEventListener('click', function () {
        updateSlide(activeSlide, 'backgroundImage', undefined);
        renderAll();
      });
    }

    // Prev / Next
    var prevBtn = document.getElementById('cs-prev-btn');
    var nextBtn = document.getElementById('cs-next-btn');
    if (prevBtn) {
      prevBtn.addEventListener('click', function () {
        var idx = getActiveIndex();
        if (idx > 0) { activeSlide = slides[idx - 1].id; renderAll(); }
      });
    }
    if (nextBtn) {
      nextBtn.addEventListener('click', function () {
        var idx = getActiveIndex();
        if (idx < slides.length - 1) { activeSlide = slides[idx + 1].id; renderAll(); }
      });
    }

    // Upload em lote
    var batchInput = document.getElementById('cs-batch-input');
    if (batchInput) {
      batchInput.addEventListener('change', function (e) {
        if (e.target.files && e.target.files.length > 0) {
          handleBatchUpload(e.target.files);
          e.target.value = ''; // reset para permitir re-upload do mesmo arquivo
        }
      });
    }

    // Exportar
    var exportBtn = document.getElementById('cs-export-btn');
    if (exportBtn) exportBtn.addEventListener('click', exportSlides);

    // Embaralhar
    var shuffleBtn = document.getElementById('cs-shuffle-btn');
    if (shuffleBtn) shuffleBtn.addEventListener('click', shuffleSlides);

    // ── Gerar Imagens com Replicate (google/imagen-4) ─────────────────────
    var genImgBtn = document.getElementById('cs-gen-images-btn');
    if (genImgBtn) {
      genImgBtn.addEventListener('click', function () {
        // Use slides que têm imagem (exclui bullets e closing que não usam imagem de fundo)
        // Se imagePrompt não estiver definido, usa headline + subheadline como fallback
        var targets = slides
          .filter(function (s) { return s.variant !== 'bullets'; })
          .map(function (s) {
            var prompt = (s.imagePrompt && s.imagePrompt.trim().length > 4)
              ? s.imagePrompt
              : s.headline + (s.subheadline ? '. ' + s.subheadline : '');
            return Object.assign({}, s, { imagePrompt: prompt });
          });
        if (targets.length === 0) {
          alert('Nenhum slide com imagem encontrado.');
          return;
        }

        var lib = document.getElementById('cs-image-library');
        var grid = document.getElementById('cs-image-lib-grid');
        var status = document.getElementById('cs-image-lib-status');
        if (!lib || !grid) return;

        lib.classList.remove('hidden');
        grid.innerHTML = '';

        // Create placeholders
        var imgMap = {};
        targets.forEach(function (s) {
          var cell = document.createElement('div');
          cell.className = 'cs-img-lib-cell';
          cell.id = 'cs-lib-cell-' + s.id;
          cell.innerHTML =
            '<div class="cs-img-lib-thumb"><div class="cs-img-lib-spinner"></div></div>' +
            '<div class="cs-img-lib-label">Slide ' + s.id + '</div>';
          grid.appendChild(cell);
          imgMap[s.id] = cell;
        });

        if (status) { status.textContent = ''; genImgBtn.disabled = true; genImgBtn.textContent = 'Gerando…'; }

        var styleEl  = document.getElementById('cs-img-style');
        var mixEl    = document.getElementById('cs-img-mix');
        var paletteEl = document.getElementById('cs-img-palette');
        var style_visual = styleEl   ? styleEl.value   : '';
        var mix_reality  = mixEl     ? mixEl.value     : '';
        var palette     = paletteEl ? paletteEl.value : '';

        // Processa as imagens de forma SEQUENCIAL para respeitar o burst=1 da Replicate
        var index = 0;
        var total = targets.length;

        function processNext() {
          if (index >= total) {
            genImgBtn.disabled = false;
            genImgBtn.textContent = 'Gerar Imagens IA';
            return;
          }
          var s = targets[index++];
          if (status) status.textContent = 'Gerando imagem para slide ' + s.id + ' (' + index + '/' + total + ')...';
          fetch('/api/carousel/generate-image', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
              prompt: s.imagePrompt,
              style_visual: style_visual,
              mix_reality: mix_reality,
              palette: palette
            }),
          })
          .then(function (r) { return r.json(); })
          .then(function (data) {
            var cell = imgMap[s.id];
            if (!cell) return;
            if (data.dataUrl) {
              var thumb = cell.querySelector('.cs-img-lib-thumb');
              thumb.innerHTML =
                '<img src="' + data.dataUrl + '" class="cs-img-lib-img" />' +
                '<div class="cs-img-lib-overlay">' +
                  '<button class="cs-img-lib-assign" data-slide="' + s.id + '" data-src="' + data.dataUrl + '" data-target="own">→ Slide ' + s.id + '</button>' +
                  '<button class="cs-img-lib-assign cs-img-lib-assign-active" data-slide="' + s.id + '" data-src="' + data.dataUrl + '" data-target="active">→ Slide atual</button>' +
                  '<button class="cs-img-lib-save" data-src="' + data.dataUrl + '" data-slide="' + s.id + '">↓ Salvar PNG</button>' +
                '</div>';
              thumb.querySelectorAll('.cs-img-lib-assign').forEach(function (btn) {
                btn.addEventListener('click', function () {
                  var slideId = btn.dataset.target === 'active' ? activeSlide : btn.dataset.slide;
                  updateSlide(slideId, 'backgroundImage', btn.dataset.src);
                  renderAll();
                });
              });
              var saveBtn = thumb.querySelector('.cs-img-lib-save');
              if (saveBtn) {
                saveBtn.addEventListener('click', function () {
                  var src = saveBtn.dataset.src;
                  var slideId = saveBtn.dataset.slide || s.id;
                  var a = document.createElement('a');
                  a.href = src;
                  a.download = 'carrossel-slide-' + String(slideId).padStart(2, '0') + '.png';
                  document.body.appendChild(a);
                  a.click();
                  document.body.removeChild(a);
                });
              }
            } else {
              var cell = imgMap[s.id];
              if (cell) {
                cell.querySelector('.cs-img-lib-thumb').innerHTML =
                  '<span class="cs-img-lib-error">' + (data.error || 'Erro') + '</span>';
              }
            }
          })
          .catch(function () {
            var cell = imgMap[s.id];
            if (cell) cell.querySelector('.cs-img-lib-thumb').innerHTML = '<span class="cs-img-lib-error">Falha</span>';
          })
          .finally(function () {
            // Pequeno intervalo para evitar bater em limites muito agressivos
            setTimeout(processNext, 250);
          });
        }

        processNext();
      });
    }

    // Close image library
    var closeLibBtn = document.getElementById('cs-image-lib-close');
    if (closeLibBtn) {
      closeLibBtn.addEventListener('click', function () {
        var lib = document.getElementById('cs-image-library');
        if (lib) lib.classList.add('hidden');
      });
    }
  }

  // ── Bootstrap ─────────────────────────────────────────────────────────────
  function init() {
    if (!document.getElementById('cs-mini-grid')) {
      // Tenta de novo em 200ms (SPA ainda pode não ter renderizado)
      setTimeout(init, 200);
      return;
    }
    bindEvents();
    renderAll();
  }

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', init);
  } else {
    init();
  }
})();

