    var a = document.createElement('a');
    a.href = dataUrl;
    a.download = 'criativo-' + (idx + 1) + '.png';
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
  } catch (e) {
    console.error('downloadImage error', e);
  }
}

